            </div>
        </div>
    </div>

    <!-- Students table -->
    <div class="card">
        <div class="table-responsive">
            <table class="table mb-0" id="students-table">
                <thead>
                    <tr>
                        <th class="px-4" style="width:120px">Roll no.</th>
                        <th>Name</th>
                        <th style="width:160px">Status</th>
                    </tr>
                </thead>
                <tbody>
                    {% for s in students %}
                    <tr id="row-{{ s.id }}">
                        <td class="px-4 text-muted small align-middle">{{ s.roll_no }}</td>
                        <td class="fw-500 align-middle">{{ s.name }}</td>
                        <td class="align-middle">
                            <div class="d-flex gap-3">
                                <div class="form-check">
                                    <input class="form-check-input status-radio" type="radio" name="status_{{ s.id }}" id="present_{{ s.id }}" value="present" onchange="updateRow({{ s.id }}, 'present')" checked/>
                                    <label class="form-check-label small" for="present_{{ s.id }}" style="color:#15803d; font-weight:500">Present</label>
                                </div>
                                <div class="form-check">
                                    <input class="form-check-input status-radio" type="radio" name="status_{{ s.id }}" id="absent_{{ s.id }}" value="absent" onchange="updateRow({{ s.id }}, 'absent')" />
                                    <label class="form-check-label small" for="absent_{{ s.id }}" style="color:#b91c1c; font-weight:500">Absent</label>
                                </div>
                            </div>
                        </td>
                    </tr>
                    {% endfor %}
                </tbody>
            </table>
        </div>
    </div>

    <div class="mt-3 d-flex gap-2">
        <button type="submit" class="btn btn-dark px-4">Save attendance</button>
        <a href="/" class="btn btn-outline-secondary">Cancel</a>
    </div>

    {% else %}
    <div class="card">
        <div class="card-body text-center text-muted py-5">
            No students found.
            <a href="/students" class="text-dark fw-500">Add students first</a>
        </div>
    </div>
    {% endif %}

</form>

<script>
    function updateCounter() {
        const radios = document.querySelectorAll('input.status-radio[value="present"]:checked');
        const total = {
            {
                students | length
            }
        };
        const present = radios.length;
        document.getElementById('present-count').textContent = present;
        document.getElementById('absent-count').textContent = total - present;
    }

    function updateRow(id, status) {
        const row = document.getElementById('row-' + id);
        row.style.background = status === 'present' ?
            'rgba(34,197,94,0.06)' :
            'rgba(239,68,68,0.06)';
        updateCounter();
    }

    function markAll(status) {
        document.querySelectorAll('input.status-radio[value="' + status + '"]')
            .forEach(r => {
                r.checked = true;
                const id = r.name.replace('status_', '');
                updateRow(id, status);
            });
        updateCounter();
    }

    // Init counter and row colours on page load (all default to present)
    document.addEventListener('DOMContentLoaded', () => {
        document.querySelectorAll('input.status-radio[value="present"]')
            .forEach(r => {
                const id = r.name.replace('status_', '');
                updateRow(id, 'present');
            });
        updateCounter();
    });
</script>

{% endblock %}

{% extends "base.html" %}
{% block content %}

<div class="d-flex align-items-center justify-content-between mb-4">
